def main():
    sheet = get_sheet(TAB_APPROVED)

    # Clear existing data rows (keep row 1 = header)
    all_values = sheet.get_all_values()
    if len(all_values) > 1:
        sheet.delete_rows(2, len(all_values))
        print(f"Cleared {len(all_values) - 1} existing rows.")

    # Sort by legitimacy_score descending so most popular appear at top of sheet
    sorted_programs = sorted(SEED_PROGRAMS, key=lambda x: int(x[13]), reverse=True)

    sheet.append_rows(sorted_programs, value_input_option="USER_ENTERED")
    print(f"Seeded {len(sorted_programs)} programs sorted by popularity (legitimacy_score desc).")


if __name__ == "__main__":
    main()
